import{_ as h}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as n,c as E,f as e,q as o,D as l,N as r,j as s,g as i,k as a,W as p}from"./chunks/runtime-core.esm-bundler.DuRo-bNR.js";const k=JSON.parse('{"title":"什么是RAG检索增强生成","description":"","frontmatter":{},"headers":[],"relativePath":"column/AIFuture/基础认知/什么是RAG检索增强生成.md","filePath":"column/AIFuture/基础认知/什么是RAG检索增强生成.md","lastUpdated":1782975799000}'),A={name:"column/AIFuture/基础认知/什么是RAG检索增强生成.md"};function c(b,t,m,g,B,_){const u=n("ArticleMetadata"),d=n("Mermaid");return e(),E("div",null,[t[2]||(t[2]=o("h1",{id:"什么是rag检索增强生成",tabindex:"-1"},[i("什么是RAG检索增强生成 "),o("a",{class:"header-anchor",href:"#什么是rag检索增强生成","aria-label":'Permalink to "什么是RAG检索增强生成"'},"​")],-1)),l(u),t[3]||(t[3]=r('<p>你有没有问过 ChatGPT 一个关于你们公司的问题，然后它一本正经地编了一个不存在的制度？</p><p>我遇到过。那一刻我就知道，光靠模型自己&quot;知道&quot;的东西，很多场景根本不够用。</p><p>这就是 RAG 要解决的问题。</p><p>RAG 全称 Retrieval-Augmented Generation，翻译过来就是<strong>检索增强生成</strong>。听着唬人，其实思路特别简单：模型回答之前，先让它去翻一下你给的资料，带着资料再回答。</p><p>不是重新训练模型，也不是把一万页文档硬塞进 prompt，而是在问答中间插一个&quot;先查后说&quot;的步骤。</p><h2 id="为什么光靠大模型不行" tabindex="-1">为什么光靠大模型不行？ <a class="header-anchor" href="#为什么光靠大模型不行" aria-label="Permalink to &quot;为什么光靠大模型不行？&quot;">​</a></h2><p>大模型确实强，但落实到实际业务里，有三个挺要命的问题：</p><ol><li><strong>你的数据它没见过</strong>：公司制度、项目文档、接口定义、客户沟通记录——这些信息从来不在训练数据里。</li><li><strong>知识会过期</strong>：模型训练完之后的事它一概不知，你的制度改了它也不知道。</li><li><strong>没依据的时候它硬编</strong>：这就是幻觉（hallucination）。问它一个它不知道的事情，它不会说不知道，而是给你编一个看起来特别像真的答案。</li></ol><p>RAG 就是把回答拴在真实资料上，让它没法瞎编。</p><h2 id="流程到底怎么跑的" tabindex="-1">流程到底怎么跑的？ <a class="header-anchor" href="#流程到底怎么跑的" aria-label="Permalink to &quot;流程到底怎么跑的？&quot;">​</a></h2><p>不复杂，就这七步：</p>',11)),(e(),s(p,null,{default:a(()=>[l(d,{id:"mermaid-50",class:"mermaid",graph:"flowchart%20TD%0A%20%20A%5B%22%E4%BD%A0%E6%8F%90%E9%97%AE%22%5D%20--%3E%20B%5B%22%E7%90%86%E8%A7%A3%2F%E6%94%B9%E5%86%99%E9%97%AE%E9%A2%98%22%5D%0A%20%20B%20--%3E%20C%5B%22%E5%8E%BB%E7%9F%A5%E8%AF%86%E5%BA%93%E9%87%8C%E6%90%9C%22%5D%0A%20%20C%20--%3E%20D%5B%22%E6%8D%9E%E7%9B%B8%E5%85%B3%E7%89%87%E6%AE%B5%22%5D%0A%20%20D%20--%3E%20E%5B%22%E9%87%8D%E6%8E%92%E8%BF%87%E6%BB%A4%22%5D%0A%20%20E%20--%3E%20F%5B%22%E6%8B%BC%E6%88%90%E4%B8%8A%E4%B8%8B%E6%96%87%22%5D%0A%20%20F%20--%3E%20G%5B%22%E6%A8%A1%E5%9E%8B%E5%9F%BA%E4%BA%8E%E8%BF%99%E4%BA%9B%E8%B5%84%E6%96%99%E5%9B%9E%E7%AD%94%22%5D%0A%20%20G%20--%3E%20H%5B%22%E7%BB%99%E4%BD%A0%E7%AD%94%E6%A1%88%EF%BC%8C%E9%99%84%E5%B8%A6%E6%9D%A5%E6%BA%90%22%5D%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[i(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=r(`<p>一句话概括就是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>提问 → 找资料 → 带资料问模型 → 出答案</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="一个真实场景" tabindex="-1">一个真实场景 <a class="header-anchor" href="#一个真实场景" aria-label="Permalink to &quot;一个真实场景&quot;">​</a></h2><p>假设你给公司搭了个 AI 助手，同事问：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>高铁一等座能报销吗？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>没 RAG 的时候</strong>：模型只能猜。它可能说&quot;大部分公司可以&quot;，也可能编出一个报销流程，但跟你公司实际制度没半毛钱关系。</p><p><strong>有 RAG 的时候</strong>：系统先去翻你们的《差旅报销制度.md》《财务审批规则.pdf》，找到相关段落，然后交给模型：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请只基于以下制度原文回答用户问题。</span></span>
<span class="line"><span>如果制度里没明确写，请直接说&quot;当前资料未提及&quot;，不要自己推断。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这样出来的答案：</p><ul><li>有明确结论</li><li>带原文引用</li><li>不确定的地方单独标出来</li><li>告诉你接下来该问谁</li></ul><p>这才是企业里真正能用的 AI。</p><h2 id="rag-里面都有啥" tabindex="-1">RAG 里面都有啥？ <a class="header-anchor" href="#rag-里面都有啥" aria-label="Permalink to &quot;RAG 里面都有啥？&quot;">​</a></h2><p>一个完整的 RAG 系统拆开来大概长这样：</p><table tabindex="0"><thead><tr><th>环节</th><th>干嘛的</th><th>容易翻车的地方</th></tr></thead><tbody><tr><td>文档采集</td><td>把 PDF、网页、数据库的东西收进来</td><td>数据源不全</td></tr><tr><td>文档清洗</td><td>去掉页眉页脚、格式乱码这些脏东西</td><td>标题层级、表格给洗没了</td></tr><tr><td>文档切片</td><td>把长文档切成一段一段方便检索</td><td>切太碎了没上下文，切太大了搜不准</td></tr><tr><td>Embedding</td><td>把文字转成向量（数值化表示）</td><td>语义理解不到位</td></tr><tr><td>向量数据库</td><td>存向量和元数据</td><td>检索慢了用户等不了</td></tr><tr><td>召回</td><td>从库里找可能相关的片段</td><td>漏掉了真正有用的</td></tr><tr><td>重排</td><td>从候选里挑真正最相关的</td><td>排在前面的其实不相关</td></tr><tr><td>生成</td><td>基于资料让模型回答</td><td>没引用来源，还是编的</td></tr><tr><td>评估</td><td>检查回答质量能不能用</td><td>不做评估就不知道改了到底有没有变好</td></tr></tbody></table><p>别被这表吓到，你刚开始做 MVP 的时候其实只用到前三列就够了，后面是优化的事了。</p><h2 id="rag-和微调-fine-tuning-到底怎么选" tabindex="-1">RAG 和微调（Fine-tuning）到底怎么选？ <a class="header-anchor" href="#rag-和微调-fine-tuning-到底怎么选" aria-label="Permalink to &quot;RAG 和微调（Fine-tuning）到底怎么选？&quot;">​</a></h2><p>这是被问得最多的问题。</p><table tabindex="0"><thead><tr><th></th><th>RAG</th><th>微调</th></tr></thead><tbody><tr><td>适合干嘛</td><td>查资料、问文档、知识经常变</td><td>学会特定风格、格式、任务习惯</td></tr><tr><td>更新数据</td><td>改知识库就行</td><td>一般得重新训</td></tr><tr><td>能追溯吗</td><td>能，答案可以标出原文来源</td><td>难，说不清为什么这么答</td></tr><tr><td>成本</td><td>工程搭建麻烦但更新灵活</td><td>训练烧钱</td></tr><tr><td>典型用法</td><td>企业知识库、客服、合同问答</td><td>分类器、风格迁移、特定的输出格式</td></tr></tbody></table><p>一个粗暴的判断方法：<strong>你需要的是一双&quot;能查资料的眼睛&quot;，还是&quot;学会某种做事方式的手&quot;？前者用 RAG，后者再考虑微调。</strong></p><p>大部分实际落地的场景，RAG 就够用了。</p><h2 id="做-rag-最容易踩的坑" tabindex="-1">做 RAG 最容易踩的坑 <a class="header-anchor" href="#做-rag-最容易踩的坑" aria-label="Permalink to &quot;做 RAG 最容易踩的坑&quot;">​</a></h2><h3 id="切片切蹦了" tabindex="-1">切片切蹦了 <a class="header-anchor" href="#切片切蹦了" aria-label="Permalink to &quot;切片切蹦了&quot;">​</a></h3><p>这是最常见的翻车点。</p><ul><li>切太大（比如一章一章的）：搜出来的东西太泛，模型找不到精确答案。</li><li>切太小（比如一句一句的）：搜到的是孤立的句子，前后因果关系全丢了。</li></ul><p>实际经验：</p><ul><li>技术文档按标题层级切</li><li>FAQ 按问答对切</li><li>制度文档按条款切</li><li>不管怎么切，前后留一点重叠，别让上下文断掉</li></ul><h3 id="只靠向量检索" tabindex="-1">只靠向量检索 <a class="header-anchor" href="#只靠向量检索" aria-label="Permalink to &quot;只靠向量检索&quot;">​</a></h3><p>向量检索擅长找&quot;意思差不多&quot;的内容，但找精确的东西不一定稳：</p><ul><li>产品型号 HX-850 和 HX-580，向量可能觉得差不多</li><li>订单号、工号、版本号，这些更适合直接用关键词匹配</li></ul><p>所以实际系统一般是混合检索：</p>`,30)),(e(),s(p,null,{default:a(()=>[l(d,{id:"mermaid-373",class:"mermaid",graph:"flowchart%20LR%0A%20%20A%5B%22%E5%85%B3%E9%94%AE%E8%AF%8D%E6%A3%80%E7%B4%A2%22%5D%20--%3E%20D%5B%22%E5%80%99%E9%80%89%E6%B1%A0%22%5D%0A%20%20B%5B%22%E5%90%91%E9%87%8F%E6%A3%80%E7%B4%A2%22%5D%20--%3E%20D%0A%20%20C%5B%22%E4%B8%9A%E5%8A%A1%E8%BF%87%E6%BB%A4%22%5D%20--%3E%20D%0A%20%20D%20--%3E%20E%5B%22%E9%87%8D%E6%8E%92%22%5D%0A%20%20E%20--%3E%20F%5B%22%E6%9C%80%E7%BB%88%E7%BB%99%E6%A8%A1%E5%9E%8B%E7%9A%84%E4%B8%8A%E4%B8%8B%E6%96%87%22%5D%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[i(" Loading... ",-1)])]),_:1})),t[5]||(t[5]=r('<h3 id="忘了权限" tabindex="-1">忘了权限 <a class="header-anchor" href="#忘了权限" aria-label="Permalink to &quot;忘了权限&quot;">​</a></h3><p>别把全公司的文档倒进一个池子，谁都能查。每个文档片段该带上部门、项目、权限级别这些标签，检索的时候该过滤就过滤。不然 HR 的数据被研发同事搜到了就尴尬了。</p><h3 id="不做评估集" tabindex="-1">不做评估集 <a class="header-anchor" href="#不做评估集" aria-label="Permalink to &quot;不做评估集&quot;">​</a></h3><p>很多人搭完 RAG 跑了一下觉得&quot;还行&quot;就上线了。过两周用户反馈说&quot;怎么搜不到&quot;的时候，你完全不知道改切片大小还是换 Embedding 模型。</p><p>提前准备四类测试题：</p><ul><li>经常被问的真实问题</li><li>容易搞混的问题（比如两个相似的制度条款）</li><li>资料里根本没有答案的问题（测它会不会瞎编）</li><li>跨部门权限的问题（测能不能拦住）</li></ul><h2 id="哪些场景值得搞-rag" tabindex="-1">哪些场景值得搞 RAG？ <a class="header-anchor" href="#哪些场景值得搞-rag" aria-label="Permalink to &quot;哪些场景值得搞 RAG？&quot;">​</a></h2><ul><li>企业制度问答（报销、请假、绩效这些）</li><li>产品文档助手（API 文档、使用手册）</li><li>内部研发知识库（架构设计、历史决策、on-call 手册）</li><li>客服辅助回复（查历史工单、产品知识）</li><li>合同条款检索（法务、采购最需要）</li><li>代码仓库问答（&quot;这个接口谁写的，干什么用的&quot;）</li><li>售前资料检索（方案、案例、报价）</li></ul><p>这些场景有一个共同点：<strong>答案必须来自资料，不能让模型拍脑袋。</strong></p><hr><p><em>延伸阅读</em></p><ul><li><a href="https://docs.langchain.com/oss/python/langchain/rag" target="_blank" rel="noreferrer">LangChain：Build a RAG agent</a></li><li><a href="https://developers.llamaindex.ai/python/framework/understanding/rag/" target="_blank" rel="noreferrer">LlamaIndex：Introduction to RAG</a></li><li><a href="https://developers.openai.com/api/docs/guides/tools-file-search" target="_blank" rel="noreferrer">OpenAI：File Search</a></li><li><a href="https://developers.openai.com/cookbook/examples/evaluation/evaluate_rag_with_llamaindex" target="_blank" rel="noreferrer">OpenAI Cookbook：Evaluate RAG with LlamaIndex</a></li></ul><hr><blockquote><p>RAG 说白了就是让大模型从&quot;凭记忆瞎猜&quot;变成&quot;翻完资料再说话&quot;。</p></blockquote>',14))])}const D=h(A,[["render",c]]);export{k as __pageData,D as default};
